graphql.query:
query GetReleases($page: Int, $limit: Int, $search: String, $status: String, $date: String, $sortDir: String) {
  releases(page: $page, limit: $limit, search: $search, status: $status, date: $date, sortDir: $sortDir) {
    data {
      id
      name
      release_date
      status
    }
    metadata {
      totalPages
      total
      page
      limit
    }
  }
}

mutation CreateRelease($name: String!, $release_date: String!, $additional_info: String) {
  createRelease(name: $name, release_date: $release_date, additional_info: $additional_info) {
    id
    name
    status
  }
}

