graphql.query:
query GetRelease($id: ID!) {
  release(id: $id) {
    id
    name
    release_date
    status
    additional_info
    steps {
      id
      name
      completed
    }
  }
}

mutation UpdateRelease($id: ID!, $status: String, $steps: [StepInput]) {
  updateRelease(id: $id, status: $status, steps: $steps) {
    id
    status
  }
}

